"use client";

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { FadeIn, SlideUp, StaggerContainer, StaggerItem } from '@/components/animations/MotionUtils';
import { apiClient, ApiError } from '@/lib/apiClient';
import { useAuth } from '@/lib/authContext';

interface TestResult {
  id: string;
  testName: string;
  marksObtained: number;
  totalMarks: number;
  testDate: string;
}

const Skeleton = ({ className = '' }: { className?: string }) => (
  <div className={`animate-pulse bg-white/5 border border-white/5 ${className}`} />
);

export default function TestResultsPage() {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading } = useAuth();
  const [results, setResults] = useState<TestResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!authLoading && !authUser) router.push('/login');
  }, [authUser, authLoading, router]);

  useEffect(() => {
    if (!authUser) return;
    const fetchResults = async () => {
      try {
        const data = await apiClient.get<TestResult[]>('/portal/tests');
        setResults(data);
      } catch (err) {
        if (err instanceof ApiError && err.status === 401) router.push('/login');
        else setError('ARCHIVE_COMM_FAILURE: PERFORMANCE_LOGS_UNREACHABLE');
      } finally {
        setLoading(false);
      }
    };
    fetchResults();
  }, [authUser, router]);

  const avgPrecision = results.length > 0
    ? Math.round(results.reduce((sum, t) => sum + (t.marksObtained / t.totalMarks) * 100, 0) / results.length)
    : 0;

  if (authLoading || loading) {
    return (
      <div className="space-y-12">
        <Skeleton className="h-4 w-32" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
           <Skeleton className="h-48" />
           <Skeleton className="h-48" />
        </div>
        <Skeleton className="h-[500px] w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-24 pb-32">
      
      <FadeIn>
        <div className="flex flex-col items-start leading-[0.85]">
          <span className="font-script text-4xl text-[#888888] lowercase mb-8 block">access the</span>
          <h1 className="text-7xl md:text-9xl font-black uppercase tracking-tighter-editorial text-white leading-[0.8]">
             Scoring <br /> <span className="text-white/20">Archive</span>
          </h1>
          <p className="text-xl text-[#888888] lowercase mt-12 max-w-xl leading-relaxed">
            a precise historical record of performance telemetry and academic evaluations.
          </p>
        </div>
      </FadeIn>

      {/* Analytics Matrix */}
      <StaggerContainer className="grid grid-cols-1 md:grid-cols-2 gap-0 overflow-hidden">
        <StaggerItem>
           <div className="p-12 border border-white/5 group hover:bg-white/[0.02] transition-all duration-700 h-full relative">
              <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-4 block italic">MATRIX_01: AVG_PRECISION</span>
              <div className="flex items-baseline gap-4 mt-8">
                 <h3 className="text-8xl font-black text-white uppercase tracking-tighter">{avgPrecision}%</h3>
                 <span className="text-xs font-black text-white/20 uppercase tracking-widest">CUMULATIVE</span>
              </div>
           </div>
        </StaggerItem>
        <StaggerItem>
           <div className="p-12 border-y border-r border-white/5 group hover:bg-white/[0.02] transition-all duration-700 h-full relative">
              <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-4 block italic">MATRIX_02: LOGS_RECORDED</span>
              <div className="flex items-baseline gap-4 mt-8">
                 <h3 className="text-8xl font-black text-white uppercase tracking-tighter">{results.length}</h3>
                 <span className="text-xs font-black text-white/20 uppercase tracking-widest">VALID_ENTRIES</span>
              </div>
           </div>
        </StaggerItem>
      </StaggerContainer>

      {/* Historical Logs */}
      <div>
        <FadeIn>
          <div className="mb-12 px-4">
             <span className="text-[10px] font-black uppercase tracking-[0.5em] text-white/20 italic">02. PERFORMANCE_HISTORY</span>
          </div>
        </FadeIn>
        
        {results.length === 0 ? (
          <div className="p-16 border border-white/5 bg-white/[0.01] text-center">
             <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#555555]">ARCHIVE_EMPTY: NO_LOGS_DETECTED</p>
          </div>
        ) : (
          <StaggerContainer className="flex flex-col divide-y divide-white/5 border-y border-white/5">
            {results.map((test, idx) => (
              <StaggerItem key={test.id}>
                <div className="group grid md:grid-cols-12 items-center py-12 px-4 hover:bg-white/[0.01] transition-all duration-500">
                  <div className="md:col-span-1 flex flex-col mb-4 md:mb-0">
                     <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.2em]">{`LOG_${(idx + 1).toString().padStart(3, '0')}`}</span>
                  </div>
                  
                  <div className="md:col-span-5 mb-4 md:mb-0">
                     <h3 className="text-3xl font-black text-white uppercase tracking-tighter group-hover:pl-4 transition-all duration-500">{test.testName}</h3>
                     <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.3em] mt-2 block">TIMESTAMP: {new Date(test.testDate).toLocaleDateString('en-IN').toUpperCase()}</span>
                  </div>

                  <div className="md:col-span-3 flex flex-col md:items-end mb-4 md:mb-0">
                     <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.2em] mb-1">SCORE_VALUE</span>
                     <span className="text-3xl font-black text-white tracking-tighter italic">{test.marksObtained} / {test.totalMarks}</span>
                  </div>

                  <div className="md:col-span-3 flex items-center md:pl-12">
                     <div className="w-full h-1 bg-white/[0.05] relative overflow-hidden">
                        <div 
                          className="absolute left-0 top-0 h-full bg-white transition-all duration-[2000ms] ease-expo group-hover:opacity-60" 
                          style={{ width: `${(test.marksObtained / test.totalMarks) * 100}%` }}
                        />
                     </div>
                     <span className="text-[10px] font-black text-white/40 ml-4 tabular-nums">{Math.round((test.marksObtained / test.totalMarks) * 100)}%</span>
                  </div>
                </div>
              </StaggerItem>
            ))}
          </StaggerContainer>
        )}
      </div>

    </div>
  );
}
